const { CallbackHandler } = require("langfuse-langchain");
const { initChatModel } = require("langchain/chat_models/universal");

// Get connected model
const model = await this.getInputConnectionData("ai_languageModel", 0);
const modelProvider = model.lc_namespace[2].replace("_", "-");
const modelName = model.model;
const temperature = model.temperature;

// Initialize Langfuse callback handler
const sessionId = $input.item.json.sessionId;
const langfuseHandler = new CallbackHandler({
  sessionId,
});

const llm = await initChatModel(modelName, {
  temperature,
  modelProvider,
  callbacks: [langfuseHandler],
});

return llm;
